   ) ;
ALTER TABLE "DIRKSPZM32"."ISI_PURCH_KOPF" ADD CONSTRAINT "CHK_ISI_PURCH_KOPF_STATUS" CHECK (STATUS in ('N','B', 'G', 'F', 'E')) ENABLE;
