ALTER TABLE "DIRKSPZM32"."ISI_PURCH_KOPF" ADD CONSTRAINT "PK_PURCH_KOPF" PRIMARY KEY ("ID")
  USING INDEX  ENABLE;
ALTER TABLE "DIRKSPZM32"."ISI_PURCH_KOPF" ADD CONSTRAINT "UK_PURCH_KOPF" UNIQUE ("RECHNUNGS_NR")
  USING INDEX  ENABLE;
ALTER TABLE "DIRKSPZM32"."ISI_PURCH_KOPF" ADD CONSTRAINT "UK_PURCH_KOPF_PF_RECH_NR" UNIQUE ("PRO_FORMA_RECH_NR")
  USING INDEX  ENABLE;


